<?php include '../php/database.php'; header('Content-Type: application/json'); $quiz_id = intval($_GET['quiz_id'] ?? 0); if($quiz_id>0){ $stmt = $conn->prepare('SELECT user_name,correct_answers,total_questions,percentage,taken_at FROM scores WHERE quiz_id=? ORDER BY taken_at DESC LIMIT 50'); $stmt->bind_param('i',$quiz_id); $stmt->execute(); $res = $stmt->get_result()->fetch_all(MYSQLI_ASSOC); } else { $res = $conn->query('SELECT user_name,correct_answers,total_questions,percentage,taken_at FROM scores ORDER BY taken_at DESC LIMIT 50')->fetch_all(MYSQLI_ASSOC); } echo json_encode($res); ?>